"descr": "\u0420\u043e\u0436\u0434\u0435\u043d\u0438\u0435 \u0417\u0432\u0435\u0440\u0435\u0432\u043e\u0439 \u041a\u043b\u0430\u0432\u0434\u0438\u0438 \u0410\u043b\u0435\u043a\u0441\u0430\u043d\u0434\u0440\u043e\u0432\u043d\u044b",
